import { AppBar, Box, Button, Dialog, DialogContent, DialogTitle, Icon, IconButton, makeStyles, TextField, Toolbar, Typography } from '@material-ui/core'
import { Assignment, AssignmentIndRounded, CloseRounded } from '@material-ui/icons'
import React from 'react'

const useStyles = makeStyles(theme => {
    return {
        root: {
            display: 'flex'
        },
        title: {
            display: 'flex',
            alignContent: 'center'
        },
        icon: {
            marginRight: theme.spacing(0.5),
            marginLeft: theme.spacing(0.5),
        },
        white: {
            color: '#fefefe'
        },
        toolbar: theme.mixins.toolbar,
        btn: {
            marginTop: theme.spacing(2)
        },
        formContainer: {
            maxWidth: theme.spacing(100),
            margin: 'auto'
        },
        appBar: {
            backgroundColor: 'rgba(0,0,0,0.2)'
        }
    }
})

function CreateActivity() {
    const classes = useStyles()


    return (
        <Box className={classes.root}>
            <Dialog open={true} fullScreen>
                <DialogTitle>
                    <AppBar color='secondary' elevation={0}>
                        <Toolbar>
                            <IconButton><CloseRounded className={classes.white} /></IconButton>
                            <Box className={classes.title}><Icon className={classes.icon}><Assignment /></Icon> Create Activity</Box>
                        </Toolbar>
                    </AppBar>
                </DialogTitle>
                <DialogContent>
                    <Box className={classes.formContainer}>
                        <Box className={classes.toolbar} />
                        <form action="">
                            <TextField
                                variant='filled'
                                type='text'
                                name='title'
                                // value={postData.title}
                                // onChange={handleChange}
                                color='secondary'
                                label='Title (Optional)'
                                margin='normal'
                                fullWidth
                                multiline
                            />

                            <TextField
                                variant='filled'
                                type='text'
                                name='body'
                                // value={postData.body}
                                // onChange={handleChange}
                                color='secondary'
                                label='Say something here...'
                                minRows={4}
                                margin='normal'
                                fullWidth
                                multiline
                                required
                            />
                            <input
                            //  onChange={handleFileChange} style={{ display: 'none' }} 
                             type="file" name='files[]' multiple id='attach-file' />
                            <label htmlFor="attach-file">
                                <IconButton component='span'><Tooltip title='Attach a file' placement='right-start' ><AttachFileRounded /></Tooltip></IconButton>
                            </label>
                            <Button className={classes.btn} variant='contained' color='secondary' fullWidth>Post</Button>
                        </form>
                    </Box>
                </DialogContent>
            </Dialog>
        </Box>
    )
}

export default CreateActivity
